const { runSynthesisAgent } = require('/opt/node_modules/recon-multiagent/dist/synthesis_agent.js');
const { runGroundingGate } = require('/opt/node_modules/recon-multiagent/dist/grounding_gate.js');
const { finalizeRun } = require('/opt/node_modules/recon-multiagent/dist/run_finalizer.js');
const { getEvidenceByRunId, getSignalsByRunId } = require('/opt/node_modules/recon-multiagent/dist/db.js');

const body = $input.first().json;
const runId = body.run_id;
const brief = body.brief;

if (!runId || !brief) {
  return [{ json: { statusCode: 400, body: { status: 'missing_run_id_or_brief' } } }];
}

const signals = await getSignalsByRunId(runId);

const synthesisResult = await runSynthesisAgent(runId, brief, {
  baseUrl: $env.DEEPINFRA_BASE_URL,
  apiKey: $env.DEEPINFRA_API_KEY,
  model: $env.MODEL_NAME ?? 'google/gemma-4-26B-A4B-it',
  temperature: 0,
});

const evidence = await getEvidenceByRunId(runId);

// Deterministic gate: citation_verifier, recast-as-gap, then dossier persistence and status.
const groundingResult = await runGroundingGate(runId, synthesisResult.dossier, signals, evidence);

const finalResult = await finalizeRun({
  runId,
  dossier: groundingResult.dossier,
  claimsTotal: groundingResult.claimsTotal,
  claimsVerified: groundingResult.claimsVerified,
  recastGaps: groundingResult.recastGaps,
  brief,
});

return [{ json: {
  statusCode: 200,
  body: {
    status: finalResult.status,
    run_id: runId,
    synthesis: {
      stopped: synthesisResult.stoppedBecause,
      repair_attempts: synthesisResult.repairAttempts,
      signal_count: synthesisResult.signalCount,
    },
    grounding: {
      claims_total: groundingResult.claimsTotal,
      claims_verified: groundingResult.claimsVerified,
      recast_gaps: groundingResult.recastGaps,
      grounding_passed: groundingResult.dossier.grounding_passed,
    },
    finalizer: {
      dumped_dossier: finalResult.dumpedDossier,
      db_id: finalResult.dbId,
    },
  },
} }];
